/**
 * widgetContract.ts
 *
 * The Scraplet Widget Contract v2
 *
 * CONSTRAINT: UnifiedOverlayState is the only state that can influence
 * rendering anywhere in the system. Widget renderers receive typed state
 * from the snapshot — they do not open connections, poll, or read globals.
 */

import type { BaseWidgetState } from '../../overlay-runtime/types/unifiedOverlayState';

// ─── Widget Renderer Contract ─────────────────────────────────────────────────

/**
 * Typed renderer props. State is the specific WidgetSubState for this widget.
 * Renderers must be pure — same state = same output, no side effects.
 */
export interface WidgetRendererProps<S extends BaseWidgetState = BaseWidgetState> {
  state: S;
  config: { instanceId: string };
  width: number;
  height: number;
}

export type WidgetRenderer<S extends BaseWidgetState = BaseWidgetState> =
  (props: WidgetRendererProps<S>) => React.ReactElement | null;

/**
 * Widget renderer registry.
 * Maps widgetId → React renderer function.
 */
export const widgetRenderers: Map<string, WidgetRenderer<any>> = new Map();

export function registerWidgetRenderer<S extends BaseWidgetState>(
  widgetId: string,
  renderer: WidgetRenderer<S>
): void {
  widgetRenderers.set(widgetId, renderer as WidgetRenderer<any>);
}

export function getWidgetRenderer(widgetId: string): WidgetRenderer<any> | undefined {
  return widgetRenderers.get(widgetId);
}

// ─── Legacy compatibility (kept during migration) ─────────────────────────────

/** @deprecated Use WidgetRendererProps<S> instead */
export interface WidgetStateEvent {
  widgetId: string;
  instanceId: string;
  state: Record<string, any>;
}

/** @deprecated Events are no longer the source of truth */
export const WIDGET_STATE_EVENT = 'scraplet:widget:state';

/** @deprecated Config flows through UnifiedOverlayState, not window globals */
export interface WidgetConfig {
  instanceId: string;
  [key: string]: any;
}
